class Solution {
    public int minimumOperationsToMakeEqual(int x, int y) {
        int res = Math.abs(x - y);
        while (x != y) {
            if (x > y) {
                if (x % 11 == 0) x /= 11;
                else if (x % 5 == 0) x /= 5;
                else x--;
            } else {
                if (y % 11 == 0) y /= 11;
                else if (y % 5 == 0) y /= 5;
                else y++;
            }
            res++;
        }
        return res;
    }
}
